import{_ as a,n as e,p as h,O as r}from"./framework-997e6189.js";const d={},i=r('<h1 id="行情牛跑酷隐私政策" tabindex="-1"><a class="header-anchor" href="#行情牛跑酷隐私政策" aria-hidden="true">#</a> 行情牛跑酷隐私政策</h1><p>生效日期：2026 年 6 月 15 日</p><p>行情牛跑酷重视用户隐私。本隐私政策说明扩展如何处理信息。</p><h2 id="数据收集" tabindex="-1"><a class="header-anchor" href="#数据收集" aria-hidden="true">#</a> 数据收集</h2><p>行情牛跑酷不收集、不存储、不出售，也不上传任何个人信息、浏览历史、账户信息或行情数据。</p><h2 id="本地处理" tabindex="-1"><a class="header-anchor" href="#本地处理" aria-hidden="true">#</a> 本地处理</h2><p>扩展仅在用户打开受支持的同花顺个股行情页面时运行。为了生成跑酷游戏路径，扩展会在用户浏览器本地临时读取当前页面上可见的 Canvas 或 SVG 行情图及页面尺寸。</p><p>这些信息只用于在当前页面中运行游戏，不会离开用户设备，也不会被持久化。</p><h2 id="权限用途" tabindex="-1"><a class="header-anchor" href="#权限用途" aria-hidden="true">#</a> 权限用途</h2><p>扩展仅请求访问 <code>https://stockpage.10jqka.com.cn/*</code>，用于读取当前可见行情图并显示游戏覆盖层。扩展不会访问其他网站。</p><h2 id="第三方共享" tabindex="-1"><a class="header-anchor" href="#第三方共享" aria-hidden="true">#</a> 第三方共享</h2><p>行情牛跑酷不会向任何第三方共享、出售或传输用户数据。</p><h2 id="远程代码与外部服务" tabindex="-1"><a class="header-anchor" href="#远程代码与外部服务" aria-hidden="true">#</a> 远程代码与外部服务</h2><p>扩展不下载或执行远程代码，不使用分析服务、广告服务或外部数据服务。</p><h2 id="政策更新" tabindex="-1"><a class="header-anchor" href="#政策更新" aria-hidden="true">#</a> 政策更新</h2><p>如果本隐私政策发生变化，更新后的内容将发布在本页面，并修改生效日期。</p><h2 id="联系方式" tabindex="-1"><a class="header-anchor" href="#联系方式" aria-hidden="true">#</a> 联系方式</h2><p>如对本隐私政策有疑问，请通过 Chrome Web Store 中显示的开发者联系方式联系开发者。</p>',18),n=[i];function t(c,s){return e(),h("div",null,n)}const p=a(d,[["render",t],["__file","index.html.vue"]]);export{p as default};
